#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <stdexcept>

void solve_question(); // Forward declaration of the student's solution function

std::string run_test_case(const std::string& input) {
    std::stringstream ss_input(input);
    std::stringstream ss_output;
    std::stringstream ss_error;

    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::streambuf* old_cerr = std::cerr.rdbuf();

    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());
    std::cerr.rdbuf(ss_error.rdbuf());

    try {
        solve_question(); 
    } catch (const std::exception& e) {
        ss_error << "Unhandled exception: " << e.what() << std::endl;
    } catch (...) {
        ss_error << "Unhandled unknown exception." << std::endl;
    }

    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);
    std::cerr.rdbuf(old_cerr);

    std::string output = ss_output.str();
    std::string error_output = ss_error.str();

    if (!error_output.empty()) {
        return "ERROR: " + error_output + output; 
    }
    return output;
}
